\end{equation}

where:
\begin{itemize}
\item $|\Omega|$ is the number of components
\item $A_{ij}$ is the connection matrix
\item $h(\psi)$ is the hierarchical depth
\item $\alpha_s, \beta_s, \gamma_s$ are weighting coefficients with $\sum \alpha_s + \beta_s + \gamma_s = 1$
\end{itemize}

\subsection{Functional Complexity}

Let $\mathcal{F}$ be the function set and $D_{ij}$ the function dependency matrix:

\begin{equation}
C_f(\psi) = \alpha_f \log_2(1 + |\mathcal{F}|) + \beta_f \left(\frac{1}{|\mathcal{F}|^2}\sum_{i,j} D_{ij}\right) + \gamma_f \log_2(1 + |S|)
\end{equation}

where $|S|$ is the size of the state space.

\subsection{Relational Complexity}

For interaction network $G$:

\begin{equation}
C_r(\psi) = \alpha_r \bar{c}(G) + \beta_r \kappa(G) + \gamma_r \left(\frac{1}{\bar{l}(G)}\right)
\end{equation}

where:
\begin{itemize}
\item $\bar{c}(G)$ is mean degree centrality
\item $\kappa(G)$ is the clustering coefficient
\item $\bar{l}(G)$ is average path length
\end{itemize}

\subsection{Temporal Complexity}

\begin{equation}
C_t(\psi) = \alpha_t \log_2(1 + \dot{\psi}) + \beta_t(1 - H_{\text{rate}}) + \gamma_t \mathcal{A}(\psi)
\end{equation}

where:
\begin{itemize}
\item $\dot{\psi}$ is state change rate
\item $H_{\text{rate}}$ is entropy rate
\item $\mathcal{A}(\psi)$ is adaptive capacity
\end{itemize}

\subsection{Total Complexity}

The total complexity is given by:

\begin{equation}
\mathcal{C}_{\text{total}}(\psi) = (C_s \cdot C_f \cdot C_r \cdot C_t)^{1/4}
\end{equation}

\subsection{Intropy}

Let $\mathcal{P}$ be the set of peace products with utilities $u_i$. The intropy $\mathcal{I}$ is:

\begin{equation}
\mathcal{I}(\psi) = \mathcal{C}_{\text{total}}(\psi) \cdot U(\mathcal{C}, \mathcal{P})
\end{equation}

where the utility function $U$ is:

\begin{equation}
U(\mathcal{C}, \mathcal{P}) = \left(\sum_{i} u_i\right) \cdot (1 - \Pi_c) \cdot (1 + B_b) \cdot (1 + B_t)
\end{equation}

\subsection{Utility Components}

\subsubsection{Complexity Penalty}
\begin{equation}
\Pi_c = \begin{cases}
0 & \text{if } \mathcal{C}_{\text{total}} \leq \theta \\
\tanh\left(\frac{\mathcal{C}_{\text{total}} - \theta}{\theta}\right) & \text{otherwise}
\end{cases}
\end{equation}

where $\theta$ is the complexity threshold.

\subsubsection{Balance Bonus}
\begin{equation}
B_b = e^{-\sigma(\mathcal{C})}
\end{equation}

where $\sigma(\mathcal{C})$ is the standard deviation of complexity components.

\subsubsection{Temporal Bonus}
For a history of complexities $\{\mathcal{C}_t\}$:

\begin{equation}
B_t = \tanh\left(\frac{1}{n-1}\sum_{i=1}^{n-1} (\mathcal{C}_{i+1} - \mathcal{C}_i)\right)
\end{equation}

\subsection{Intropy Landscape}

The intropy landscape $\mathcal{L}$ is defined as:

\begin{equation}
\mathcal{L}(\psi) = \{l_s, l_f, l_r, l_t\}
\end{equation}

where each component is:

\begin{equation}
l_k = C_k \cdot U(\mathcal{C}, \mathcal{P}), \quad k \in \{s,f,r,t\}
\end{equation}

